public String stoneGameIII(int[] stoneValue) {
    int n = stoneValue.length;
    int[] dp = new int[n + 1];
    dp[n] = 0;

    for (int i = n - 1; i >= 0; --i) {
        dp[i] = Integer.MIN_VALUE;
        int curr = 0;
        for (int j = 0; j < 3 && i + j < n; ++j) {
            curr += stoneValue[i + j];
            dp[i] = Math.max(dp[i], curr - dp[i + j + 1]);
        }
    }

    return dp[0] == 0 ? "Tie " : dp[0] > 0 ? "Alice " : "Bob ";
}
